import sys
import functools

def main():
    sys.setrecursionlimit(1000000)
    N = int(sys.stdin.readline())

    @functools.lru_cache(maxsize=None)
    def f(x):
        if x < 2:
            return 0
        return x + f(x // 2) + f((x + 1) // 2)

    print(f(N))

if __name__ == "__main__":
    main()
